    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.compress.archivers.zip.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.compress.archivers.zip.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.apache.commons.compress.archivers.zip.ZipArchiveEntry;

public class StepDefs {
    private ZipArchiveEntry entry;
    private boolean result;

    @Given("a ZipArchiveEntry with a Unix mode of 0160000")
    public void a_zip_archive_entry_with_a_unix_mode_of_0160000() {
        // 0160000 corresponds to LINK_FLAG (0120000) | DIR_FLAG (040000)
        entry = new ZipArchiveEntry("test");
        try {
            // Using reflection to set the internal field for the unix mode
            java.lang.reflect.Field field = ZipArchiveEntry.class.getDeclaredField("unixMode");
            field.setAccessible(true);
            field.set(entry, 0160000);
        } catch (Exception e) {
            // Handle exception in case of reflection issues
            fail("Failed to set unix mode: " + e.getMessage());
        }
    }

    @When("I check if the entry is a Unix symlink")
    public void i_check_if_the_entry_is_a_unix_symlink() {
        try {
            result = entry.isUnixSymlink();
        } catch (Exception e) {
            // Handle any exception that may occur
            result = false;  // Default to false if an exception occurs during the check
        }
    }

    @Then("the result should be false")
    public void the_result_should_be_false() {
        assertEquals("The result should be false when multiple file type flags are set", false, result);
    }
}

