/**
 * Returns true if this entry represents a unix symlink,
 * in which case the entry's content contains the target path
 * for the symlink.
 *
 * @since 1.5
 * @return true if the entry represents a unix symlink, false otherwise.
 */
public boolean isUnixSymlink() {
    // Extract only the file type bits and check if they match exactly the link flag
    int fileType = getUnixMode() & (UnixStat.FILE_FLAG | UnixStat.DIR_FLAG | UnixStat.LINK_FLAG);
    return fileType == UnixStat.LINK_FLAG;
}

